sql.where:
l.user_id = #{query.userId}

    AND l.create_time >= #{query.startTime}


    AND l.create_time <= #{query.endTime}


    AND l.tool_name LIKE CONCAT('%', #{query.toolName}, '%')


    AND l.backend_id = #{query.backendId}



    AND COALESCE(l.server_name_snapshot, bk.server_name, b.server_name, legacy_b.server_name) LIKE CONCAT('%', #{query.serverName}, '%')


    AND COALESCE(l.user_email_snapshot, u.email) LIKE CONCAT('%', #{query.userEmail}, '%')


    AND COALESCE(l.token_prefix_snapshot, t.token_prefix) LIKE CONCAT('%', #{query.tokenPrefix}, '%')



    AND l.success = #{query.success}


    AND l.cost_ms >= #{query.minCostMs}

mapper.select:
SELECT COUNT(*) AS totalCount, SUM(CASE WHEN l.success = 1 AND l.cost_ms < #{timeoutMs} THEN 1 ELSE 0 END) AS successCount, SUM(CASE WHEN l.success = 1 AND l.cost_ms >= #{timeoutMs} THEN 1 ELSE 0 END) AS timeoutCount, SUM(CASE WHEN l.success = 0 THEN 1 ELSE 0 END) AS failedCount, AVG(l.cost_ms) AS avgCostMs, MAX(l.cost_ms) AS maxCostMs, MIN(l.cost_ms) AS minCostMs FROM mcp_call_log l WHERE l.user_id = #{userId}
AND l.create_time >= #{startTime}
AND l.create_time <= #{endTime}

SELECT * FROM (
    SELECT 'SUCCESS' AS status,
           SUM(CASE WHEN l.success = 1 AND l.cost_ms < #{timeoutMs} THEN 1 ELSE 0 END) AS cnt
    FROM mcp_call_log l
    WHERE l.user_id = #{userId}

        AND l.create_time >= #{startTime}


        AND l.create_time <= #{endTime}

    UNION ALL
    SELECT 'FAILED' AS status,
           SUM(CASE WHEN l.success = 0 THEN 1 ELSE 0 END) AS cnt
    FROM mcp_call_log l
    WHERE l.user_id = #{userId}

        AND l.create_time >= #{startTime}


        AND l.create_time <= #{endTime}

    UNION ALL
    SELECT 'TIMEOUT' AS status,
           SUM(CASE WHEN l.success = 1 AND l.cost_ms >= #{timeoutMs} THEN 1 ELSE 0 END) AS cnt
    FROM mcp_call_log l
    WHERE l.user_id = #{userId}

        AND l.create_time >= #{startTime}


        AND l.create_time <= #{endTime}

) t
ORDER BY status

SELECT
    HOUR(create_time) AS hour,
    COUNT(*) AS invokeCount,
    SUM(CASE WHEN success = 0 OR cost_ms >= 1800000 THEN 1 ELSE 0 END) AS errorCount
FROM mcp_call_log l
WHERE l.user_id = #{userId}

    AND l.create_time >= #{startTime}


    AND l.create_time <= #{endTime}

GROUP BY HOUR(create_time)
ORDER BY hour

SELECT l.id, l.tool_name AS toolName, l.backend_id AS backendId, COALESCE(l.server_name_snapshot, bk.server_name, b.server_name, legacy_b.server_name) AS backendName, l.transport_type AS transportType, l.cost_ms AS costMs, l.success, l.error_code AS errorCode, l.create_time AS invokedAt FROM mcp_call_log l
WHERE l.user_id = #{userId}
AND l.create_time >= #{startTime}
AND l.create_time <= #{endTime}
ORDER BY l.cost_ms DESC LIMIT #{limit}
